arguments.new_str:
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Pages;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Components;
using ShipmentTracker.Components.Account;
using ShipmentTracker.Data;
using ShipmentTracker.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents()
    .AddAuthenticationStateSerialization();

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<IdentityRedirectManager>();
builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();

builder.Services.AddAuthentication(options =>
    {
        options.DefaultScheme = IdentityConstants.ApplicationScheme;
        options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
    })
    .AddIdentityCookies();

var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlite(connectionString));
builder.Services.AddDatabaseDeveloperPageExceptionFilter();

builder.Services.AddIdentityCore<ApplicationUser>(options =>
    {
        options.SignIn.RequireConfirmedAccount = true;
        options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
    })
    .AddRoles<IdentityRole>()
    .AddEntityFrameworkStores<ApplicationDbContext>()
    .AddSignInManager()
    .AddDefaultTokenProviders();

builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();
builder.Services.AddScoped<IShipmentService, ServerShipmentService>();

var app = builder.Build();

// Seed database
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    db.Database.Migrate();

    var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
    if (!await roleManager.RoleExistsAsync("Dispatcher"))
        await roleManager.CreateAsync(new IdentityRole("Dispatcher"));
    if (!await roleManager.RoleExistsAsync("Customer"))
        await roleManager.CreateAsync(new IdentityRole("Customer"));

    if (!db.Shipments.Any())
    {
        db.Shipments.AddRange(
            new Shipment { TrackingNumber = "TRK-001-2026", Origin = "New York, USA", Destination = "London, UK", Status = ShipmentStatus.InTransit, ShippedDate = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(4), CustomerEmail = "alice@example.com", Description = "Electronics - Laptop" },
            new Shipment { TrackingNumber = "TRK-002-2026", Origin = "Shanghai, China", Destination = "Los Angeles, USA", Status = ShipmentStatus.PickedUp, ShippedDate = DateTime.UtcNow.AddDays(-1), EstimatedDelivery = DateTime.UtcNow.AddDays(12), CustomerEmail = "bob@example.com", Description = "Furniture - Office Desk" },
            new Shipment { TrackingNumber = "TRK-003-2026", Origin = "Berlin, Germany", Destination = "Tokyo, Japan", Status = ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow, CustomerEmail = "charlie@example.com", Description = "Auto Parts" },
            new Shipment { TrackingNumber = "TRK-004-2026", Origin = "Sydney, Australia", Destination = "Dubai, UAE", Status = ShipmentStatus.Delivered, ShippedDate = DateTime.UtcNow.AddDays(-10), EstimatedDelivery = DateTime.UtcNow.AddDays(-2), CustomerEmail = "diana@example.com", Description = "Medical Supplies" },
            new Shipment { TrackingNumber = "TRK-005-2026", Origin = "São Paulo, Brazil", Destination = "Mumbai, India", Status = ShipmentStatus.Delayed, ShippedDate = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "eve@example.com", Description = "Textiles" },
            new Shipment { TrackingNumber = "TRK-006-2026", Origin = "Toronto, Canada", Destination = "Paris, France", Status = ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(6), CustomerEmail = "frank@example.com", Description = "Food Products - Perishable" }
        );
        db.SaveChanges();
    }
}

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
    app.UseMigrationsEndPoint();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

// API endpoints for shipment data (used by WebAssembly client)
app.MapGet("api/shipments", async (ApplicationDbContext db) =>
    await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync())
    .RequireAuthorization();

app.MapGet("api/shipments/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});

app.MapPut("api/shipments/{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments.FindAsync(id);
    if (shipment is null) return Results.NotFound();
    shipment.Status = status;
    await db.SaveChangesAsync();
    return Results.Ok();
}).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

app.Run();

