    {
        ShipmentStatus.Pending => "Pending Pickup",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered ✓",
        ShipmentStatus.Delayed => "Delayed",
        _ => status.ToString()
    };

    private static int GetProgressPercentage(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger progress-bar-striped progress-bar-animated",
        ShipmentStatus.OutForDelivery => "bg-warning",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };
}

